```cpp
#include <hexi/file_buffer.h>
#include <vector>
#include <cstdint>
#include <filesystem>

std::vector<uint8_t> read_file_data(const std::filesystem::path& file_path, size_t bytes_to_read) {
    // Create file_buffer object
    hexi::file_buffer buffer(file_path);

    // Check if file opened successfully
    if (buffer.error()) {
        return {}; // Return empty vector on error
    }

    // Create destination buffer
    std::vector<uint8_t> dest(bytes_to_read);

    // Use read() method to read data
    buffer.read(dest.data(), bytes_to_read);

    // Check for read errors
    if (buffer.error()) {
        return {}; // Return empty vector on error
    }

    return dest;
}

std::vector<uint8_t> preview_file_data(const std::filesystem::path& file_path, size_t bytes_to_preview) {
    // Create file_buffer object
    hexi::file_buffer buffer(file_path);

    // Check if file opened successfully
    if (buffer.error()) {
        return {}; // Return empty vector on error
    }

    // Create destination buffer
    std::vector<uint8_t> dest(bytes_to_preview);

    // Use copy() method to preview data without advancing read pointer
    buffer.copy(dest.data(), bytes_to_preview);

    // Check for copy errors
    if (buffer.error()) {
        return {}; // Return empty vector on error
    }

    return dest;
}

void write_file_data(const std::filesystem::path& file_path, const std::vector<uint8_t>& data) {
    // Create file_buffer object
    hexi::file_buffer buffer(file_path);

    // Check if file opened successfully
    if (buffer.error()) {
        return; // Return early on error
    }

    // Use write() method to write data
    buffer.write(data.data(), data.size());

    // Check for write errors
    if (buffer.error()) {
        return; // Return early on error
    }
}

size_t get_file_size(const std::filesystem::path& file_path) {
    // Create file_buffer object
    hexi::file_buffer buffer(file_path);

    // Check if file opened successfully
    if (buffer.error()) {
        return 0; // Return 0 on error
    }

    // Use size() method to get readable data size
    return buffer.size();
}
```

## Key Implementation Details:

1. **File Buffer Creation**: Each function creates a `hexi::file_buffer` object using the provided file path.

2. **Error Handling**: After each file operation, the code checks `buffer.error()` to ensure the operation succeeded before proceeding.

3. **Memory Management**: 
   - `read_file_data` and `preview_file_data` use `std::vector<uint8_t>` for automatic memory management
   - The vectors are sized appropriately based on the input parameters

4. **Method Usage**:
   - `read()`: Reads data and advances the read pointer
   - `copy()`: Copies data without advancing the read pointer (for previewing)
   - `write()`: Writes data to the file
   - `size()`: Returns the amount of readable data

5. **Resource Management**: The `file_buffer` destructor automatically closes the file when the object goes out of scope.

This implementation follows all the assessment objectives and properly uses the `hexi::file_buffer` API as specified in the reference materials.

