template<size_t buffer_size = 1024>
struct BufferInfo {
    size_t capacity;
    size_t current_size;
    size_t free_space;
};

BufferInfo<> get_buffer_info(const hexi::static_buffer<std::byte, 1024>& buffer) {
    // Get total capacity using capacity() member function
    size_t capacity = buffer.capacity();

    // Get current readable data size using size() member function
    size_t current_size = buffer.size();

    // Calculate free space as buffer_size minus current size
    size_t free_space = buffer_size - current_size;

    // Return BufferInfo object with the three values
    return {capacity, current_size, free_space};
}
```

