#include <hexi/pmc/binary_stream_reader.h>
#include <hexi/pmc/buffer_adaptor.h>
#include <vector>
#include <cstdint>

struct UserData {
    uint32_t user_id;
    std::string name;

    void serialise(auto& stream) {
        stream << user_id << name;
    }
};

void serialize_object(hexi::pmc::binary_stream_writer& writer, const UserData& data) {
    // Create a buffer to hold the serialized data
    std::vector<std::byte> buffer;

    // Create a buffer_adaptor for the buffer
    hexi::pmc::buffer_adaptor<std::vector<std::byte>> adaptor(buffer);

    // Create a binary_stream_writer using the buffer_adaptor
    hexi::pmc::binary_stream_writer writer(adaptor);

    // Call the object's serialise method with the writer
    data.serialise(writer);
}

void deserialize_object(hexi::pmc::binary_stream_reader& reader, UserData& data) {
    // Create a buffer to hold the serialized data
    std::vector<std::byte> buffer;

    // Create a buffer_adaptor for the buffer
    hexi::pmc::buffer_adaptor<std::vector<std::byte>> adaptor(buffer);

    // Create a binary_stream_reader using the buffer_adaptor
    hexi::pmc::binary_stream_reader reader(adaptor);

    // Call the object's serialise method with the reader
    data.serialise(reader);
}
```

## Explanation:

### Serialization Process:
1. **Buffer Creation**: A `std::vector<std::byte>` is created to store the serialized data.
2. **Buffer Adaptor**: A `buffer_adaptor` wraps the vector to provide the buffer interface required by the binary streams.
3. **Stream Writer**: A `binary_stream_writer` is created using the buffer adaptor.
4. **Serialization**: The object's `serialise` method is called with the writer, which uses the stream operators (`<<`) to serialize the `user_id` and `name` fields.

### Deserialization Process:
1. **Buffer Creation**: A `std::vector<std::byte>` is created to hold the serialized data.
2. **Buffer Adaptor**: A `buffer_adaptor` wraps the vector to provide the buffer interface.
3. **Stream Reader**: A `binary_stream_reader` is created using the buffer adaptor.
4. **Deserialization**: The object's `serialise` method is called with the reader, which uses the stream operators (`>>`) to deserialize the `user_id` and `name` fields.

The key insight is that the same `serialise` method works for both serialization and deserialization because the stream adaptor automatically adapts to whether it's being used for writing or reading based on the type of stream passed to it.

