#include <hexi/pmc/buffer_read_adaptor.h>
#include <hexi/pmc/buffer_write_adaptor.h>
#include <vector>
#include <cstdint>

std::size_t write_multiple_chunks(const std::vector<std::vector<uint8_t>>& chunks) {
    // Create a buffer_write_adaptor instance
    std::vector<uint8_t> buffer;
    hexi::pmc::buffer_write_adaptor<std::vector<uint8_t>> adaptor(buffer);

    std::size_t total_written = 0;

    // Iterate through each chunk in the input vector
    for (const auto& chunk : chunks) {
        if (chunk.empty()) continue; // Skip empty chunks

        // Before each write, check available space using free()
        std::size_t available_space = adaptor.free();
        if (chunk.size() > available_space) {
            // Handle insufficient space (could throw exception or return error)
            // For this implementation, we'll skip writing if space is insufficient
            continue;
        }

        // Write the chunk data using write()
        adaptor.write(chunk.data(), chunk.size());
        total_written += chunk.size();
    }

    // After all writes, return the total size using size()
    return adaptor.size();
}

std::vector<uint8_t> read_partial_data(const std::vector<uint8_t>& buffer, std::size_t chunk_size) {
    // Create a buffer_read_adaptor instance
    hexi::pmc::buffer_read_adaptor<const std::vector<uint8_t>> adaptor(buffer);

    std::vector<uint8_t> result;

    // Use a loop that continues until the buffer is empty
    while (adaptor.size() > 0) {
        // In each iteration, calculate how much to read (minimum of chunk_size and remaining size)
        std::size_t read_size = std::min(chunk_size, adaptor.size());

        // Read the data using read()
        std::vector<uint8_t> temp_chunk(read_size);
        adaptor.read(temp_chunk.data(), read_size);

        // Append the read data to the result vector
        result.insert(result.end(), temp_chunk.begin(), temp_chunk.end());
    }

    return result;
}
