struct MeasurementData {
    uint32_t sensor_id;
    std::vector<float> temperatures;
    double pressure;

    void serialise(auto& adaptor) const {
        // Write sensor_id directly
        adaptor.write(sensor_id);

        // Convert and write each temperature using conditional_reverse
        for (auto temp : temperatures) {
            float converted = hexi::endian::conditional_reverse(temp, std::endian::native, std::endian::little);
            adaptor.write(converted);
        }

        // Convert and write pressure using conditional_reverse
        double converted_pressure = hexi::endian::conditional_reverse(pressure, std::endian::native, std::endian::little);
        adaptor.write(converted_pressure);
    }

    void deserialise(auto& adaptor) {
        // Read sensor_id directly
        adaptor >> sensor_id;

        // Read and convert each temperature using little_to_native_inplace
        for (auto& temp : temperatures) {
            adaptor >> temp;
            hexi::endian::little_to_native_inplace(temp);
        }

        // Read and convert pressure using little_to_native_inplace
        adaptor >> pressure;
        hexi::endian::little_to_native_inplace(pressure);
    }
};

std::vector<uint8_t> serialize_measurement_data(const MeasurementData& data) {
    // Create buffer and binary_stream
    std::vector<uint8_t> buffer;
    hexi::binary_stream<std::vector<uint8_t>> adaptor(buffer);

    // Serialize the data
    data.serialise(adaptor);

    return buffer;
}

